import{_ as l,o as e,c as o,ag as n}from"./chunks/framework.CTpQozEL.js";const f=JSON.parse('{"title":"Northflank","description":"원클릭 템플릿으로 Northflank에 OpenClaw 배포","frontmatter":{"title":"Northflank","description":"원클릭 템플릿으로 Northflank에 OpenClaw 배포"},"headers":[],"relativePath":"install/northflank.md","filePath":"install/northflank.md","lastUpdated":null}'),t={name:"install/northflank.md"};function r(i,a,c,s,h,d){return e(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="northflank" tabindex="-1">Northflank <a class="header-anchor" href="#northflank" aria-label="Permalink to &quot;Northflank&quot;">​</a></h1><p>원클릭 템플릿으로 Northflank에 OpenClaw를 배포하고 웹 Control UI를 통해 접근합니다. &quot;서버에 터미널 없음&quot; 경로 중 가장 쉬운 방법입니다 — Northflank가 게이트웨이를 대신 실행해 줍니다.</p><h2 id="시작하는-방법" tabindex="-1">시작하는 방법 <a class="header-anchor" href="#시작하는-방법" aria-label="Permalink to &quot;시작하는 방법&quot;">​</a></h2><ol><li><a href="https://northflank.com/stacks/deploy-openclaw" target="_blank" rel="noreferrer">Deploy OpenClaw</a> 를 클릭해 템플릿을 엽니다.</li><li>계정이 없다면 <a href="https://app.northflank.com/signup" target="_blank" rel="noreferrer">Northflank 가입</a> 을 진행합니다.</li><li><strong>Deploy OpenClaw now</strong> 를 클릭합니다.</li><li>필수 환경 변수를 설정합니다: <code>OPENCLAW_GATEWAY_TOKEN</code> (강력한 랜덤 값을 사용).</li><li><strong>Deploy stack</strong> 을 클릭해 OpenClaw 템플릿을 빌드 및 실행합니다.</li><li>배포 완료를 기다린 다음 <strong>View resources</strong> 를 클릭합니다.</li><li>OpenClaw 서비스를 엽니다.</li><li><code>/openclaw</code>의 공개 OpenClaw URL을 열고 설정한 공유 시크릿으로 연결합니다. 이 템플릿은 기본적으로 <code>OPENCLAW_GATEWAY_TOKEN</code> 을 사용합니다. 비밀번호 인증으로 교체했다면 해당 비밀번호를 사용합니다.</li></ol><h2 id="제공되는-것" tabindex="-1">제공되는 것 <a class="header-anchor" href="#제공되는-것" aria-label="Permalink to &quot;제공되는 것&quot;">​</a></h2><ul><li>호스팅된 OpenClaw Gateway + Control UI</li><li>Northflank Volume(<code>/data</code>) 을 통한 영구 저장소 — <code>openclaw.json</code>, 에이전트별 <code>auth-profiles.json</code>, 채널/프로바이더 상태, 세션, 워크스페이스가 재배포 후에도 유지됩니다.</li></ul><h2 id="채널-연결" tabindex="-1">채널 연결 <a class="header-anchor" href="#채널-연결" aria-label="Permalink to &quot;채널 연결&quot;">​</a></h2><p><code>/openclaw</code>의 Control UI를 사용하거나 SSH를 통해 <code>openclaw onboard</code> 를 실행해 채널 설정 방법을 확인합니다:</p><ul><li><a href="/openclaw-docs-ko/channels/telegram">Telegram</a> (가장 빠름 — 봇 토큰만 있으면 됨)</li><li><a href="/openclaw-docs-ko/channels/discord">Discord</a></li><li><a href="/openclaw-docs-ko/channels/">모든 채널</a></li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><ul><li>메시징 채널 설정: <a href="/openclaw-docs-ko/channels/">채널</a></li><li>게이트웨이 구성: <a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a></li><li>OpenClaw 최신 상태 유지: <a href="/openclaw-docs-ko/install/updating">업데이트</a></li></ul>',11)])])}const k=l(t,[["render",r]]);export{f as __pageData,k as default};
